    def _create_plain_text_content(self, article_data: Dict[str, Any]) -> str:
        """
        创建纯文本邮件内容（备用）

        Args:
            article_data: 文章数据

        Returns:
            纯文本格式的邮件内容
        """
        title = article_data.get("title", "未知标题")
        summary = article_data.get("summary", "")
        source_url = article_data.get("source_url", "")
        local_path = article_data.get("local_path", "")

        text = f"""
{'='*60}
{title}
{'='*60}

📋 文章摘要
{summary if summary else '（无摘要内容）'}

🔗 原文链接: {source_url}
💾 本地保存: {local_path if local_path else '（未保存）'}
📅 抓取时间: {article_data.get('fetch_time', '未知时间')}

📖 完整内容
（完整内容请查看HTML版本或访问原文链接）

{'='*60}
本邮件由 AIByHand-Digest 系统自动生成
定时抓取自: byhand.ai | 摘要生成: DeepSeek API
如需退订或调整推送频率，请回复此邮件
© 2026 AIByHand-Digest 自动化系统
        """
        return text.strip()

    def send_article(self, article_data: Dict[str, Any]) -> bool:
        """
        发送文章摘要邮件

        Args:
            article_data: 文章数据字典，包含:
                - title: 文章标题
                - summary: 文章摘要
                - content: 文章正文（HTML格式）
                - source_url: 原文链接
                - local_path: 本地保存路径
                - fetch_time: 抓取时间

        Returns:
            发送成功返回True，失败返回False
        """
        if not self.email_config["enabled"]:
            logger.info("邮箱推送功能已禁用")
            return False

        recipients = self.email_config["recipients"]
        if not recipients:
            logger.error("未配置收件人列表")
            return False

        smtp_server = self.email_config["smtp_server"]
        smtp_port = self.email_config["smtp_port"]
        smtp_username = self.email_config["smtp_username"]
        smtp_password = self.email_config["smtp_password"]
        sender_name = self.email_config["sender_name"]

        if not smtp_username or not smtp_password:
            logger.error("邮箱用户名或密码未配置")
            return False

        try:
            # 创建邮件
            msg = MIMEMultipart('alternative')
            msg['Subject'] = Header(
                f"{self.email_config['subject_prefix']}{article_data.get('title', 'AI文章摘要')}",
                'utf-8'
            )
            msg['From'] = f"{sender_name} <{smtp_username}>"
            msg['To'] = ", ".join(recipients)

            # 添加纯文本版本（备用）
            plain_text = self._create_plain_text_content(article_data)
            msg.attach(MIMEText(plain_text, 'plain', 'utf-8'))

            # 添加HTML版本
            html_content = self._create_html_content(article_data)
            msg.attach(MIMEText(html_content, 'html', 'utf-8'))

            # 连接SMTP服务器并发送
            context = ssl.create_default_context()

            logger.info(f"正在连接SMTP服务器: {smtp_server}:{smtp_port}")
            with smtplib.SMTP(smtp_server, smtp_port) as server:
                server.ehlo()
                server.starttls(context=context)
                server.ehlo()
                server.login(smtp_username, smtp_password)
                server.sendmail(smtp_username, recipients, msg.as_string())

            logger.info(f"邮件发送成功: {article_data.get('title', '未知标题')}")
            logger.info(f"收件人: {', '.join(recipients)}")
            return True

        except smtplib.SMTPAuthenticationError:
            logger.error("SMTP认证失败，请检查用户名和密码")
            logger.error("提示：Gmail需要应用专用密码，非登录密码")
        except smtplib.SMTPException as e:
            logger.error(f"SMTP错误: {e}")
        except Exception as e:
            logger.error(f"邮件发送失败: {e}")

        return False

    def test_connection(self) -> bool:
        """
        测试SMTP连接和认证

        Returns:
            连接成功返回True，失败返回False
        """
        smtp_server = self.email_config["smtp_server"]
        smtp_port = self.email_config["smtp_port"]
        smtp_username = self.email_config["smtp_username"]
        smtp_password = self.email_config["smtp_password"]

        if not smtp_username or not smtp_password:
            logger.error("邮箱用户名或密码未配置")
            return False

        try:
            context = ssl.create_default_context()
            with smtplib.SMTP(smtp_server, smtp_port) as server:
                server.ehlo()
                server.starttls(context=context)
                server.ehlo()
                server.login(smtp_username, smtp_password)
                logger.info("SMTP连接测试成功")
                return True
        except smtplib.SMTPAuthenticationError:
            logger.error("SMTP认证失败，请检查用户名和密码")
        except smtplib.SMTPException as e:
            logger.error(f"SMTP连接失败: {e}")
        except Exception as e:
            logger.error(f"连接测试失败: {e}")

        return False


# 快捷函数
def send_article_email(article_data: Dict[str, Any]) -> bool:
    """快捷函数：发送文章邮件"""
    sender = EmailSender()
    return sender.send_article(article_data)


def test_email_connection() -> bool:
    """快捷函数：测试邮箱连接"""
    sender = EmailSender()
    return sender.test_connection()


if __name__ == "__main__":
    # 配置日志
    logging.basicConfig(
        level=logging.INFO,
        format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
    )

    print("邮箱推送模块测试")
    print("=" * 50)

    # 测试连接
    print("\n1. 测试SMTP连接...")
    if test_email_connection():
        print("✓ SMTP连接测试成功")
    else:
        print("✗ SMTP连接测试失败")
        print("请检查配置是否正确")
        exit(1)

    # 测试发送示例邮件
    print("\n2. 测试发送示例邮件...")
    example_article = {
        "title": "测试文章：PPO → DPO → GRPO→ Rubrics",
        "summary": "这是一篇测试摘要，用于验证邮箱推送功能。文章讨论了从PPO到DPO再到GRPO的强化学习算法演进，最终介绍了Rubrics评分标准在RL研究中的应用。",
        "content": "<p>这是测试文章的完整内容。</p><p>文章详细介绍了强化学习算法的演进历程...</p>",
        "source_url": "https://www.byhand.ai/p/test-article",
        "local_path": "E:\\Obsidian Vault\\2026-03-06-测试文章.md",
        "fetch_time": "2026-03-06 17:30:00"
    }

    # 询问是否发送测试邮件
    print("\n是否发送测试邮件到配置的收件人？(y/n)")
    user_input = input().strip().lower()

    if user_input == 'y':
